import { initializeApp } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-app.js";
import { getFirestore, doc, setDoc, onSnapshot, serverTimestamp } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js";

const firebaseConfig = {
   apiKey: "AIzaSyBLsD-KkQ3NcjVC_sOirZ1eghLEa9fiPHc",
            authDomain: "test-3ebe7.firebaseapp.com",
            projectId: "test-3ebe7",
            storageBucket: "test-3ebe7.firebasestorage.app",
            messagingSenderId: "387247578853",
            appId: "1:387247578853:web:ca4c68e63a27f6d8f4fe0c"
};

const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

// DOM 元素
const adminModal = document.getElementById('admin-modal');
const openAdminBtn = document.getElementById('open-admin-btn');
const closeAdminBtn = document.getElementById('close-admin-btn');
const sendBtn = document.getElementById('send-btn');
const noticeInput = document.getElementById('notice-input');

const pannel = document.getElementById('notification-pannel');
const contentArea = document.getElementById('notice-content');
const manualCloseBtn = document.getElementById('manual-close-btn');

let isFirstLoad = true;
let autoCloseTimer = null;

// --- 管理員彈窗控制 ---

// 開啟彈窗
openAdminBtn.addEventListener('click', () => {
    adminModal.style.display = 'flex';
});

// 關閉彈窗
closeAdminBtn.addEventListener('click', () => {
    adminModal.style.display = 'none';
});

// 點擊遮罩層外部也可以關閉
window.addEventListener('click', (e) => {
    if (e.target === adminModal) {
        adminModal.style.display = 'none';
    }
});

// --- 發送通知邏輯 ---
sendBtn.addEventListener('click', async () => {
    const text = noticeInput.value.trim();
    if (!text) return;

    try {
        await setDoc(doc(db, "notifications", "current"), {
            content: text,
            timestamp: serverTimestamp() 
        });
        noticeInput.value = ''; 
        adminModal.style.display = 'none'; // 發送成功後自動關閉彈窗
    } catch (error) {
        console.error("發送失敗：", error);
    }
});

// --- 訪客接收邏輯 (不讀取舊紀錄) ---
onSnapshot(doc(db, "notifications", "current"), (snapshot) => {
    if (snapshot.exists()) {
        if (isFirstLoad) {
            isFirstLoad = false;
            return;
        }

        const data = snapshot.data();
        if (data.content) {
            displayNotice(data.content);
        }
    }
});

function displayNotice(message) {
    if (autoCloseTimer) clearTimeout(autoCloseTimer);
    contentArea.innerText = message;
    pannel.style.display = 'block';
    autoCloseTimer = setTimeout(() => { hideNotice(); }, 10000);
}

function hideNotice() {
    pannel.style.display = 'none';
}

manualCloseBtn.addEventListener('click', () => {
    hideNotice();
    if (autoCloseTimer) clearTimeout(autoCloseTimer);
});